import{_ as t,a,b as n,c as d}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as i,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Adding a Yandex Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/yandex.md","filePath":"en/upload/yandex.md","lastUpdated":1781962217000}'),l={name:"en/upload/yandex.md"};function p(c,e,h,u,m,b){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="adding-a-yandex-channel" tabindex="-1">Adding a Yandex Channel <a class="header-anchor" href="#adding-a-yandex-channel" aria-label="Permalink to &quot;Adding a Yandex Channel&quot;">​</a></h1><h2 id="what-you-need-first" tabindex="-1">What You Need First <a class="header-anchor" href="#what-you-need-first" aria-label="Permalink to &quot;What You Need First&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Why You Need It</th></tr></thead><tbody><tr><td>A Yandex account</td><td>Used to sign in and authorize Yandex Disk</td></tr><tr><td>A Yandex OAuth app</td><td>Used to generate the <code>Client ID</code> and <code>Client Secret</code></td></tr><tr><td>Your ImgBed domain</td><td>Used for the OAuth redirect URI</td></tr><tr><td>Available Yandex Disk storage</td><td>Used as the actual file storage location</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-create-a-yandex-oauth-app" tabindex="-1">Step 1: Create a Yandex OAuth App <a class="header-anchor" href="#step-1-create-a-yandex-oauth-app" aria-label="Permalink to &quot;Step 1: Create a Yandex OAuth App&quot;">​</a></h3><ol><li>Open the Yandex OAuth app creation page:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>If you are redirected to sign in, sign in with your Yandex account first.</li><li>Create a new app.</li><li>Give the app a recognizable name, such as <code>imgbed-yandex</code>.</li><li>Find the callback or redirect URL settings.</li><li>Enter:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-confirm-permissions" tabindex="-1">Step 2: Confirm Permissions <a class="header-anchor" href="#step-2-confirm-permissions" aria-label="Permalink to &quot;Step 2: Confirm Permissions&quot;">​</a></h3><p>For the current ImgBed Yandex integration, keep these four permissions under <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Allows ImgBed to store files in the app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Reads files and download links</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Uploads files, creates folders, and deletes files</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Reads disk quota and used space</td></tr></tbody></table><p>If you also see these permissions under <code>Yandex ID API</code>, they are optional:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>Core upload, download, deletion, and quota features mainly depend on the four <code>Yandex.Disk REST API</code> permissions above.</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-copy-app-credentials" tabindex="-1">Step 3: Copy App Credentials <a class="header-anchor" href="#step-3-copy-app-credentials" aria-label="Permalink to &quot;Step 3: Copy App Credentials&quot;">​</a></h3><p>After the app is created, copy:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-fill-in-the-yandex-channel" tabindex="-1">Step 4: Fill in the Yandex Channel <a class="header-anchor" href="#step-4-fill-in-the-yandex-channel" aria-label="Permalink to &quot;Step 4: Fill in the Yandex Channel&quot;">​</a></h3><p>In Upload Settings, choose <code>Yandex</code> and fill in:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A recognizable name, such as <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>The Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>The Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>Leave it empty for now</td></tr><tr><td>Root directory</td><td>Optional. Defaults to <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-get-the-refresh-token" tabindex="-1">Step 5: Get the Refresh Token <a class="header-anchor" href="#step-5-get-the-refresh-token" aria-label="Permalink to &quot;Step 5: Get the Refresh Token&quot;">​</a></h3><ol><li>In ImgBed, click <code>Get Token</code>.</li><li>Sign in to the Yandex account you want to connect.</li><li>Approve the authorization prompt.</li><li>The callback page will show a <code>Refresh Token</code>.</li><li>Copy it.</li><li>Return to ImgBed and paste it into the <code>Refresh Token</code> field.</li></ol><p><img src="'+d+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-save-the-channel" tabindex="-1">Step 6: Save the Channel <a class="header-anchor" href="#step-6-save-the-channel" aria-label="Permalink to &quot;Step 6: Save the Channel&quot;">​</a></h3><p>After all fields are filled in, save the channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Create an app</span></span>
<span class="line"><span>-&gt; Add https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Confirm Yandex Disk permissions</span></span>
<span class="line"><span>-&gt; Copy Client ID and Client Secret</span></span>
<span class="line"><span>-&gt; Fill Client ID / Client Secret into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=o(l,[["render",p]]);export{x as __pageData,k as default};
